import type { PathResult } from '@shared/pathfinding/types'
import type { NavFloor, NavNode } from '@shared/types'
import { useMemo } from 'react'

// ============================================================
// Types
// ============================================================

export type StepIcon =
  | 'straight'
  | 'turn-left'
  | 'turn-right'
  | 'sharp-left'
  | 'sharp-right'
  | 'arrive'
  | 'accessible'
  | 'stairs-up'
  | 'stairs-down'
  | 'elevator'
  | 'ramp'

export interface DirectionStep {
  /** Human-readable instruction, e.g. "Turn left at the cafeteria" */
  instruction: string
  icon: StepIcon
  /** Segment distance in normalized units (0–1 coordinate space) */
  distanceM: number
  /** Estimated seconds for this segment */
  durationSec: number
  /** True if this segment passes through a ramp or elevator node */
  isAccessibleSegment: boolean
}

export interface DirectionsResult {
  steps: DirectionStep[]
  /** Sum of all segment distances in normalized units */
  totalDistanceNorm: number
  /** Sum of all step durations in seconds */
  totalDurationSec: number
}

// ============================================================
// Constants
// ============================================================

const WALKING_SPEED_STANDARD = 0.023 // normalized units/s
const WALKING_SPEED_ACCESSIBLE = 0.013 // normalized units/s

/** Node types that are visible/searchable destinations — eligible for landmark references */
const LANDMARK_TYPES = new Set(['room', 'landmark', 'entrance', 'elevator', 'restroom'])

// ============================================================
// Private helpers
// ============================================================

/**
 * Compute compass bearing in degrees (0–360) from point A to point B.
 * Uses screen-space convention: x increases right, y increases down.
 * atan2(dx, -dy) gives a bearing where 0°=north, 90°=east, 180°=south, 270°=west.
 */
function bearing(ax: number, ay: number, bx: number, by: number): number {
  const dx = bx - ax
  const dy = by - ay
  // atan2(x, -y) → clockwise from north in screen-space
  const rad = Math.atan2(dx, -dy)
  const deg = (rad * 180) / Math.PI
  return (deg + 360) % 360
}

/**
 * Normalize an angle difference to the range [-180, 180].
 */
function normalizeDelta(delta: number): number {
  let d = delta % 360
  if (d > 180) d -= 360
  if (d < -180) d += 360
  return d
}

/**
 * Euclidean distance between two normalized coordinate points.
 */
function euclideanDist(ax: number, ay: number, bx: number, by: number): number {
  const dx = bx - ax
  const dy = by - ay
  return Math.sqrt(dx * dx + dy * dy)
}

/**
 * Classify bearing delta into a step icon.
 */
function classifyTurn(
  delta: number,
): Exclude<StepIcon, 'arrive' | 'accessible' | 'stairs-up' | 'stairs-down' | 'elevator' | 'ramp'> {
  const abs = Math.abs(delta)
  if (abs < 30) return 'straight'
  if (abs < 120) return delta > 0 ? 'turn-right' : 'turn-left'
  return delta > 0 ? 'sharp-right' : 'sharp-left'
}

/**
 * Build the instruction text for a direction step at the current (middle) node.
 * Appends " at the {label}" when the node is a searchable landmark-type.
 */
function buildInstruction(
  icon: Exclude<StepIcon, 'accessible' | 'stairs-up' | 'stairs-down' | 'elevator' | 'ramp'>,
  node: NavNode,
): string {
  const base: Record<
    Exclude<StepIcon, 'accessible' | 'stairs-up' | 'stairs-down' | 'elevator' | 'ramp'>,
    string
  > = {
    straight: 'Continue straight',
    'turn-left': 'Turn left',
    'turn-right': 'Turn right',
    'sharp-left': 'Sharp left',
    'sharp-right': 'Sharp right',
    arrive: `Arrive at ${node.label}`,
  }

  const text = base[icon]

  // For non-arrive steps: append landmark reference if the node is a visible, searchable destination
  if (icon !== 'arrive' && LANDMARK_TYPES.has(node.type) && node.searchable) {
    return `${text} at the ${node.label}`
  }

  return text
}

// ============================================================
// Core function
// ============================================================

/**
 * Convert an ordered list of node IDs into turn-by-turn walking directions.
 *
 * Algorithm:
 * - 0 or 1 nodes → empty result
 * - 2 nodes → single "arrive" step (no turn to compute)
 * - N nodes → for each triple (prev, curr, next): classify bearing delta → build step
 *             then append final "arrive" step for the last node
 */
export function generateDirections(
  nodeIds: string[],
  nodeMap: Map<string, NavNode>,
  mode: 'standard' | 'accessible',
  floorMap: Map<number, NavFloor> = new Map(),
): DirectionsResult {
  if (nodeIds.length < 2) {
    return { steps: [], totalDistanceNorm: 0, totalDurationSec: 0 }
  }

  const speed = mode === 'accessible' ? WALKING_SPEED_ACCESSIBLE : WALKING_SPEED_STANDARD
  const steps: DirectionStep[] = []
  let totalDistanceNorm = 0

  // Process intermediate nodes (all except the first and last)
  for (let i = 1; i < nodeIds.length - 1; i++) {
    // noUncheckedIndexedAccess: bounds are guaranteed by the for-loop condition
    const prevId = nodeIds[i - 1] as string
    const currId = nodeIds[i] as string
    const nextId = nodeIds[i + 1] as string

    // Nodes are guaranteed to be in the map when the caller provides valid IDs
    const prev = nodeMap.get(prevId)
    const curr = nodeMap.get(currId)
    const next = nodeMap.get(nextId)
    if (prev === undefined || curr === undefined || next === undefined) continue

    const distanceM = euclideanDist(prev.x, prev.y, curr.x, curr.y)
    const durationSec = distanceM / speed

    // Floor-change detection: check if curr→next crosses a floor boundary
    if (curr.floorId !== next.floorId) {
      // Determine direction icon based on connector type and vertical direction
      let icon: StepIcon
      if (curr.type === 'stairs') {
        icon = next.floorId > curr.floorId ? 'stairs-up' : 'stairs-down'
      } else if (curr.type === 'elevator') {
        icon = 'elevator'
      } else if (curr.type === 'ramp') {
        icon = 'ramp'
      } else {
        // Fallback: should not occur in a well-formed graph
        icon = 'stairs-up'
      }

      // Determine connector type name for instruction text
      const connectorTypeName =
        curr.type === 'elevator' ? 'elevator' : curr.type === 'ramp' ? 'ramp' : 'stairs'

      // Look up destination floor number; fall back to next.floorId if not in map
      const destFloor = floorMap.get(next.floorId)
      const floorNumber = destFloor?.floorNumber ?? next.floorId
      const instruction = `Take the ${connectorTypeName} to Floor ${floorNumber}`

      const isAccessibleSegment = curr.type === 'elevator' || curr.type === 'ramp'

      steps.push({ instruction, icon, distanceM, durationSec, isAccessibleSegment })
      totalDistanceNorm += distanceM
      continue
    }

    const inBearing = bearing(prev.x, prev.y, curr.x, curr.y)
    const outBearing = bearing(curr.x, curr.y, next.x, next.y)
    const delta = normalizeDelta(outBearing - inBearing)

    const icon = classifyTurn(delta)
    const instruction = buildInstruction(icon, curr)
    const isAccessibleSegment = curr.type === 'ramp' || curr.type === 'elevator'

    steps.push({ instruction, icon, distanceM, durationSec, isAccessibleSegment })
    totalDistanceNorm += distanceM
  }

  // Final "arrive" step — distance from second-to-last to last node
  const lastPrevId = nodeIds[nodeIds.length - 2] as string
  const lastId = nodeIds[nodeIds.length - 1] as string
  const lastPrev = nodeMap.get(lastPrevId)
  const last = nodeMap.get(lastId)
  if (lastPrev === undefined || last === undefined) {
    return { steps: [], totalDistanceNorm: 0, totalDurationSec: 0 }
  }

  const arriveDistance = euclideanDist(lastPrev.x, lastPrev.y, last.x, last.y)
  const arriveDuration = arriveDistance / speed
  const arriveInstruction = buildInstruction('arrive', last)

  steps.push({
    instruction: arriveInstruction,
    icon: 'arrive',
    distanceM: arriveDistance,
    durationSec: arriveDuration,
    isAccessibleSegment: last.type === 'ramp' || last.type === 'elevator',
  })

  totalDistanceNorm += arriveDistance
  const totalDurationSec = steps.reduce((sum, s) => sum + s.durationSec, 0)

  return { steps, totalDistanceNorm, totalDurationSec }
}

// ============================================================
// routesAreIdentical utility
// ============================================================

/**
 * Returns true only if both routes were found and share the exact same ordered node IDs.
 */
export function routesAreIdentical(a: PathResult, b: PathResult): boolean {
  if (!a.found || !b.found) return false
  if (a.nodeIds.length !== b.nodeIds.length) return false
  return a.nodeIds.every((id, i) => id === b.nodeIds[i])
}

// ============================================================
// Hook
// ============================================================

/**
 * Memoized hook that converts a PathResult into turn-by-turn walking directions.
 *
 * Returns an empty result when:
 * - pathResult is null
 * - pathResult.found is false
 * - pathResult has fewer than 2 nodeIds
 */
export function useRouteDirections(
  pathResult: PathResult | null,
  nodeMap: Map<string, NavNode>,
  mode: 'standard' | 'accessible',
  floorMap?: Map<number, NavFloor>,
): DirectionsResult {
  return useMemo(() => {
    if (pathResult === null || !pathResult.found) {
      return { steps: [], totalDistanceNorm: 0, totalDurationSec: 0 }
    }
    return generateDirections(pathResult.nodeIds, nodeMap, mode, floorMap)
  }, [pathResult, nodeMap, mode, floorMap])
}

import type { PathResult } from '@shared/pathfinding/types'
import type { NavNode } from '@shared/types'
import { useEffect, useRef, useState } from 'react'
import type { DirectionStep, DirectionsResult, StepIcon } from '../hooks/useRouteDirections'

// ============================================================
// Props
// ============================================================

export interface DirectionsSheetProps {
  open: boolean
  standard: PathResult | null
  accessible: PathResult | null
  standardDirections: DirectionsResult
  accessibleDirections: DirectionsResult
  routesIdentical: boolean
  activeMode: 'standard' | 'accessible'
  onTabChange: (mode: 'standard' | 'accessible') => void
  onBack: () => void
  startNode: NavNode | null
  destNode: NavNode | null
}

// ============================================================
// Helpers
// ============================================================

function formatDuration(sec: number): string {
  if (sec < 60) return `${Math.round(sec)}s`
  const mins = Math.round(sec / 60)
  return `${mins} min`
}

// ============================================================
// Sub-components
// ============================================================

interface TabButtonProps {
  mode: 'standard' | 'accessible'
  activeMode: 'standard' | 'accessible'
  found: boolean
  color: string
  label: string
  onTabChange: (mode: 'standard' | 'accessible') => void
  disabledTitle?: string
}

function TabButton({
  mode,
  activeMode,
  found,
  color,
  label,
  onTabChange,
  disabledTitle,
}: TabButtonProps) {
  const isActive = activeMode === mode
  const isDisabled = disabledTitle !== undefined && !found

  if (isDisabled) {
    return (
      <button
        type="button"
        disabled
        title={disabledTitle}
        className="flex-1 flex items-center justify-center gap-1.5 px-3 py-1.5 rounded-full text-sm font-medium bg-slate-100 text-slate-400 cursor-not-allowed opacity-60"
      >
        <span className="w-2 h-2 rounded-full bg-slate-300 inline-block shrink-0" />
        {label}
      </button>
    )
  }

  if (isActive) {
    return (
      <button
        type="button"
        onClick={() => onTabChange(mode)}
        className="flex-1 flex items-center justify-center gap-1.5 px-3 py-1.5 rounded-full text-sm font-medium transition-colors"
        style={{
          backgroundColor: `${color}1a`,
          color,
        }}
      >
        <span
          className="w-2 h-2 rounded-full inline-block shrink-0"
          style={{ backgroundColor: color }}
        />
        {label}
      </button>
    )
  }

  return (
    <button
      type="button"
      onClick={() => onTabChange(mode)}
      className="flex-1 flex items-center justify-center gap-1.5 px-3 py-1.5 rounded-full text-sm font-medium bg-slate-100 text-slate-500 hover:bg-slate-200 transition-colors"
    >
      <span className="w-2 h-2 rounded-full bg-slate-400 inline-block shrink-0" />
      {label}
    </button>
  )
}

// ============================================================
// Step icon SVGs
// ============================================================

function StepIconComponent({ icon }: { icon: StepIcon }) {
  switch (icon) {
    case 'straight':
      return (
        <svg
          width="16"
          height="16"
          viewBox="0 0 16 16"
          fill="none"
          xmlns="http://www.w3.org/2000/svg"
          aria-hidden="true"
        >
          <title>Straight</title>
          <path
            d="M8 13V3M8 3L5 6M8 3L11 6"
            stroke="currentColor"
            strokeWidth="1.5"
            strokeLinecap="round"
            strokeLinejoin="round"
          />
        </svg>
      )
    case 'turn-left':
      return (
        <svg
          width="16"
          height="16"
          viewBox="0 0 16 16"
          fill="none"
          xmlns="http://www.w3.org/2000/svg"
          aria-hidden="true"
        >
          <title>Turn left</title>
          <path
            d="M11 13V7a3 3 0 0 0-3-3H5M5 4L3 6l2 2"
            stroke="currentColor"
            strokeWidth="1.5"
            strokeLinecap="round"
            strokeLinejoin="round"
          />
        </svg>
      )
    case 'turn-right':
      return (
        <svg
          width="16"
          height="16"
          viewBox="0 0 16 16"
          fill="none"
          xmlns="http://www.w3.org/2000/svg"
          aria-hidden="true"
        >
          <title>Turn right</title>
          <path
            d="M5 13V7a3 3 0 0 1 3-3h3m0 0l2 2-2 2"
            stroke="currentColor"
            strokeWidth="1.5"
            strokeLinecap="round"
            strokeLinejoin="round"
          />
        </svg>
      )
    case 'sharp-left':
      return (
        <svg
          width="16"
          height="16"
          viewBox="0 0 16 16"
          fill="none"
          xmlns="http://www.w3.org/2000/svg"
          aria-hidden="true"
        >
          <title>Sharp left</title>
          <path
            d="M12 13V8a4 4 0 0 0-4-4H4M4 4L2 7l3 1"
            stroke="currentColor"
            strokeWidth="1.5"
            strokeLinecap="round"
            strokeLinejoin="round"
          />
        </svg>
      )
    case 'sharp-right':
      return (
        <svg
          width="16"
          height="16"
          viewBox="0 0 16 16"
          fill="none"
          xmlns="http://www.w3.org/2000/svg"
          aria-hidden="true"
        >
          <title>Sharp right</title>
          <path
            d="M4 13V8a4 4 0 0 1 4-4h4m0 0l2 3-3 1"
            stroke="currentColor"
            strokeWidth="1.5"
            strokeLinecap="round"
            strokeLinejoin="round"
          />
        </svg>
      )
    case 'arrive':
      return (
        <svg
          width="16"
          height="16"
          viewBox="0 0 16 16"
          fill="none"
          xmlns="http://www.w3.org/2000/svg"
          aria-hidden="true"
        >
          <title>Arrive</title>
          <circle cx="8" cy="8" r="6" stroke="currentColor" strokeWidth="1.5" />
          <path
            d="M5.5 8L7 9.5L10.5 6"
            stroke="currentColor"
            strokeWidth="1.5"
            strokeLinecap="round"
            strokeLinejoin="round"
          />
        </svg>
      )
    case 'accessible':
      return (
        <svg
          width="16"
          height="16"
          viewBox="0 0 16 16"
          fill="none"
          xmlns="http://www.w3.org/2000/svg"
          aria-hidden="true"
        >
          <title>Accessible</title>
          <circle cx="8" cy="3" r="1.5" fill="currentColor" />
          <path
            d="M8 5v4l2 3M6 8H4M10 13a3 3 0 1 1-4.5-2.6"
            stroke="currentColor"
            strokeWidth="1.3"
            strokeLinecap="round"
            strokeLinejoin="round"
          />
        </svg>
      )
    default:
      return null
  }
}

// ============================================================
// Step list item
// ============================================================

function StepItem({ step }: { step: DirectionStep }) {
  return (
    <div className="flex items-start gap-3 px-4 py-3 border-b border-slate-50 last:border-0">
      <div className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center shrink-0 mt-0.5 text-slate-600">
        <StepIconComponent icon={step.icon} />
      </div>
      <div className="flex-1 min-w-0">
        <p className="text-sm text-slate-800">{step.instruction}</p>
        {step.durationSec > 0 && (
          <p className="text-xs text-slate-400 mt-0.5">{formatDuration(step.durationSec)}</p>
        )}
      </div>
      {step.isAccessibleSegment && (
        <span className="text-xs px-1.5 py-0.5 rounded bg-green-50 text-green-700 shrink-0">
          ♿
        </span>
      )}
    </div>
  )
}

// ============================================================
// BackArrowIcon
// ============================================================

function BackArrowIcon() {
  return (
    <svg
      width="20"
      height="20"
      viewBox="0 0 20 20"
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
      aria-hidden="true"
    >
      <title>Back</title>
      <path
        d="M12 4L6 10L12 16"
        stroke="currentColor"
        strokeWidth="1.5"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
    </svg>
  )
}

// ============================================================
// Main component — custom bottom sheet (no Vaul)
//
// Renders as position:fixed bottom-0 — only covers the visible
// peek/expanded area. No full-viewport overlay. No pointer-event
// blocking above the sheet.
// ============================================================

const PEEK_HEIGHT = 260 // px — header + handle + first step hint
const EXPANDED_MAX = 0.92 // fraction of window height

export function DirectionsSheet({
  open,
  standard,
  accessible,
  standardDirections,
  accessibleDirections,
  routesIdentical,
  activeMode,
  onTabChange,
  onBack,
  startNode,
  destNode,
}: DirectionsSheetProps) {
  const [expanded, setExpanded] = useState(false)
  const sheetRef = useRef<HTMLElement>(null)

  // Reset to peek whenever sheet opens
  useEffect(() => {
    if (open) setExpanded(false)
  }, [open])

  // Drag state
  const dragStartY = useRef<number | null>(null)
  const dragStartExpanded = useRef(false)

  function onDragStart(clientY: number) {
    dragStartY.current = clientY
    dragStartExpanded.current = expanded
  }

  function onDragMove(clientY: number) {
    if (dragStartY.current === null) return
    const dy = dragStartY.current - clientY // positive = dragging up
    if (dy > 40) setExpanded(true)
    if (dy < -40) setExpanded(false)
  }

  function onDragEnd() {
    dragStartY.current = null
  }

  // Determine which directions to show
  const activeDirections = activeMode === 'standard' ? standardDirections : accessibleDirections

  // Case 1: Neither route found
  const neitherFound =
    (standard === null || standard.found === false) &&
    (accessible === null || accessible.found === false)

  // Duration line
  const durationText =
    routesIdentical || activeMode === 'standard'
      ? formatDuration(standardDirections.totalDurationSec)
      : formatDuration(accessibleDirections.totalDurationSec)

  const expandedHeight = `${Math.round(window.innerHeight * EXPANDED_MAX)}px`
  const currentHeight = expanded ? expandedHeight : `${PEEK_HEIGHT}px`

  if (!open) return null

  return (
    <section
      ref={sheetRef}
      aria-label="Route directions"
      className="fixed inset-x-0 bottom-0 z-50 flex flex-col rounded-t-2xl bg-white shadow-2xl"
      style={{
        height: currentHeight,
        transition: 'height 0.35s cubic-bezier(0.32, 0.72, 0, 1)',
      }}
    >
      {/* Drag handle */}
      <div
        className="shrink-0 flex justify-center pt-3 pb-1 cursor-grab active:cursor-grabbing touch-none"
        onPointerDown={(e) => {
          e.currentTarget.setPointerCapture(e.pointerId)
          onDragStart(e.clientY)
        }}
        onPointerMove={(e) => onDragMove(e.clientY)}
        onPointerUp={() => onDragEnd()}
        onPointerCancel={() => onDragEnd()}
      >
        <div className="h-1.5 w-10 rounded-full bg-gray-300" />
      </div>

      {/* Header row: back arrow + route summary */}
      <div className="flex items-center gap-2 px-4 pt-2 pb-2 border-b border-slate-100 shrink-0">
        <button
          type="button"
          onClick={onBack}
          aria-label="Back to search"
          className="p-1 text-slate-500 hover:text-slate-700"
        >
          <BackArrowIcon />
        </button>
        <div className="flex-1 min-w-0">
          <p className="text-sm font-semibold text-slate-800 truncate">
            {startNode?.label ?? '—'} → {destNode?.label ?? '—'}
          </p>
          {!neitherFound && <p className="text-xs text-slate-500">{durationText}</p>}
        </div>
        {/* Expand / collapse toggle */}
        <button
          type="button"
          onClick={() => setExpanded((e) => !e)}
          aria-label={expanded ? 'Collapse directions' : 'Expand directions'}
          className="p-1 text-slate-400 hover:text-slate-600 transition-transform"
          style={{ transform: expanded ? 'rotate(180deg)' : 'none' }}
        >
          <svg width="16" height="16" viewBox="0 0 16 16" fill="none" aria-hidden="true">
            <title>Toggle</title>
            <path
              d="M4 6L8 10L12 6"
              stroke="currentColor"
              strokeWidth="1.5"
              strokeLinecap="round"
              strokeLinejoin="round"
            />
          </svg>
        </button>
      </div>

      {/* Scrollable content — only visible when expanded */}
      <div className="flex-1 overflow-y-auto">
        {/* Case 1: No route found */}
        {neitherFound && (
          <div className="px-5 py-8 text-center text-slate-500">
            <p className="text-lg font-medium">No route found</p>
            <p className="text-sm mt-1">No path connects the selected locations.</p>
          </div>
        )}

        {/* Case 2: Routes identical — single tab chip */}
        {!neitherFound && routesIdentical && (
          <>
            <div className="px-4 pt-2 pb-1 shrink-0">
              <span className="inline-flex items-center gap-1.5 px-3 py-1 rounded-full text-xs font-medium bg-blue-50 text-blue-700">
                <span className="w-2 h-2 rounded-full bg-blue-500 inline-block" />
                Standard (accessible)
              </span>
            </div>
            <div className="pb-10">
              {standardDirections.steps.map((step, i) => (
                // biome-ignore lint/suspicious/noArrayIndexKey: steps are ordered and stable within a single route render
                <StepItem key={i} step={step} />
              ))}
            </div>
          </>
        )}

        {/* Case 3: Two distinct routes */}
        {!neitherFound && !routesIdentical && (
          <>
            <div className="flex gap-2 px-4 pt-3 pb-2 shrink-0">
              <TabButton
                mode="standard"
                activeMode={activeMode}
                found={standard?.found ?? false}
                color="#3b82f6"
                label="Standard"
                onTabChange={onTabChange}
              />
              <TabButton
                mode="accessible"
                activeMode={activeMode}
                found={accessible?.found ?? false}
                color="#22c55e"
                label="Accessible"
                onTabChange={onTabChange}
                {...(accessible?.found === false
                  ? { disabledTitle: 'No accessible route available' }
                  : {})}
              />
            </div>
            <div className="pb-10">
              {activeDirections.steps.map((step, i) => (
                // biome-ignore lint/suspicious/noArrayIndexKey: steps are ordered and stable within a single route render
                <StepItem key={i} step={step} />
              ))}
            </div>
          </>
        )}
      </div>
    </section>
  )
}

